+                | Poll::Ready(crate::cancel::CancelResult::CancellationIgnored(Err(err))) => {
+                    Poll::Ready(Err(BridgeError::Service(err)))
+                }
+                Poll::Ready(crate::cancel::CancelResult::Cancelled) => {
